  ('medical-tech-moex-20693', 'medical-tech', 'medical-tech-moex-093-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '重肌無力症（myasthenia gravis）是一種自體免疫疾病，為體內產生下列何者的抗體所致？ 腎上腺素受體（adrenergic receptor）  乙醯膽鹼受體（acetylcholine receptor） 乙醯膽鹼水解酵素（acetylcholine esterase）  多巴胺受體（dopamine receptor）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:16+00:00", "source_pdf_sha1": "c666316c921a", "answer_pdf_sha1": "c8ad2e506300", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
